 namespace Pmpr\Common\Foundation\Manipulate; use Pmpr\Common\Foundation\DOMCrawler; class ManipulateValidation extends Manipulate { public static function isURL($THMbr) : bool { return filter_var($THMbr, FILTER_VALIDATE_URL); } public static function isHtml($THMbr, $gClFP = null) { $MMkey = $THMbr != strip_tags($THMbr); if (!($MMkey && $gClFP)) { goto gl4tp; } $MMkey = DOMCrawler::has($THMbr, $gClFP); gl4tp: return $MMkey; } public static function isEnglish($THMbr) { return strlen($THMbr) == strlen(utf8_decode($THMbr)); } public static function isEmail($lRFBl) : bool { return is_email($lRFBl); } public static function isPhone($lrZWs) : bool { return is_string($lrZWs) && preg_match("\x2f\x5e\x28\134\53\71\70\77\51\x3f\173\77\x28\x30\x3f\71\133\x30\55\71\x5d\x7b\x39\175\x7d\77\x29\x24\57", $lrZWs, $PL8ty); } }
